module mux8to1_4bit (
    input [2:0] sel,
    input [3:0] in0,
    input [3:0] in1,
    input [3:0] in2,
    input [3:0] in3,
    input [3:0] in4,
    input [3:0] in5,
    input [3:0] in6,
    input [3:0] in7,
    output [3:0] out
);

    reg [3:0] mux_out;  // Multiplexer output register

    always @(*) begin
        case (sel)
            3'b000: mux_out = in0;
            3'b001: mux_out = in1;
            3'b010: mux_out = in2;
            3'b011: mux_out = in3;
            3'b100: mux_out = in4;
            3'b101: mux_out = in5;
            3'b110: mux_out = in6;
            3'b111: mux_out = in7;
            default: mux_out = 4'b0000;  // Default case (should not occur)
        endcase
    end

    wire __out_tmp = mux_out;
    assign out = __out_tmp;

endmodule
